func svgResource(name, viewBox, path string) fyne.Resource {
	data := []byte(`<svg xmlns="http://www.w3.org/2000/svg" viewBox="` + viewBox + `"><path fill="#000000" d="` + path + `"/></svg>`)
	return fyne.NewStaticResource(name, data)
}
